SELECT COUNT(DISTINCT sample_id) AS spectroscopic_samples_count
FROM snia_samples
WHERE collection_method = 'spectroscopic';

SELECT case_name, perc_snia
FROM snia_samples
ORDER BY perc_snia DESC;

SELECT sample_id, case_name, n_snia, perc_snia, collection_date
FROM snia_samples
ORDER BY perc_snia DESC;

SELECT perc_snia
FROM snia_samples
ORDER BY perc_snia DESC;

SELECT DISTINCT strftime('%Y', collection_date) AS year
FROM snia_samples
ORDER BY year ASC;

SELECT case_name, perc_snia
FROM snia_samples
WHERE perc_snia = (SELECT MAX(perc_snia) FROM snia_samples);
